<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  :root {
    --bg: #11131a;
    --panel: #1d2029;
    --panel-2: #252936;
    --panel-3: #303544;
    --line: #3a4050;
    --text: #f0f1f5;
    --muted: #a9afbf;
    --accent: #e95420;
    --accent-light: #ff753f;
    --shadow: 0 24px 60px rgba(0,0,0,.48);
  }

  * { box-sizing: border-box; }
  html, body { width: 100%; height: 100%; margin: 0; overflow: hidden; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    color: var(--text);
    background: #0d0f14;
  }

  #desktop {
    position: relative;
    width: 100vw;
    height: 100vh;
    min-height: 520px;
    overflow: hidden;
    background:
      radial-gradient(circle at 72% 28%, rgba(233,84,32,.22), transparent 28%),
      radial-gradient(circle at 19% 82%, rgba(69,49,109,.35), transparent 34%),
      linear-gradient(135deg, #141621 0%, #242033 47%, #171923 100%);
  }

  #desktop::before {
    content: "";
    position: absolute;
    inset: 0;
    opacity: .16;
    background-image: linear-gradient(115deg, transparent 0 45%, rgba(255,255,255,.12) 45.2% 45.5%, transparent 45.7%);
    background-size: 380px 380px;
    pointer-events: none;
  }

  #topbar {
    height: 38px;
    position: absolute;
    left: 0; right: 0; top: 0;
    z-index: 20;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 16px;
    background: rgba(19,21,28,.9);
    border-bottom: 1px solid rgba(255,255,255,.06);
    font-size: 13px;
  }
  .brand { font-weight: 600; letter-spacing: .2px; }
  .status { color: var(--muted); display: flex; gap: 18px; }

  #taskbar {
    position: absolute;
    z-index: 30;
    left: 50%;
    bottom: 16px;
    transform: translateX(-50%);
    display: flex;
    gap: 8px;
    padding: 8px;
    border: 1px solid rgba(255,255,255,.1);
    border-radius: 14px;
    background: rgba(25,27,35,.88);
    box-shadow: 0 12px 30px rgba(0,0,0,.35);
    backdrop-filter: blur(12px);
  }

  .launcher {
    width: 48px;
    height: 48px;
    border: 0;
    border-radius: 10px;
    color: white;
    background: transparent;
    cursor: pointer;
    font-size: 24px;
    transition: background .15s, transform .15s;
  }
  .launcher:hover { background: var(--panel-3); transform: translateY(-2px); }
  .launcher small { display: block; font-size: 9px; margin-top: 1px; color: var(--muted); }

  .window {
    position: absolute;
    z-index: 5;
    display: none;
    flex-direction: column;
    width: 560px;
    height: 390px;
    min-width: 360px;
    min-height: 240px;
    overflow: hidden;
    border: 1px solid #454b5c;
    border-radius: 10px;
    background: var(--panel);
    box-shadow: var(--shadow);
  }
  .window.visible { display: flex; }
  #files-window { left: 12%; top: 13%; }
  #notepad-window { left: 30%; top: 20%; width: 600px; height: 410px; }

  .win-titlebar {
    flex: 0 0 42px;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 0 12px 0 16px;
    background: linear-gradient(#303542, #292d39);
    border-bottom: 1px solid var(--line);
    cursor: grab;
    user-select: none;
  }
  .win-titlebar:active { cursor: grabbing; }
  .win-title { flex: 1; font-size: 14px; font-weight: 600; }
  .win-icon { font-size: 17px; }
  .win-close {
    width: 25px;
    height: 25px;
    border: 0;
    border-radius: 50%;
    color: #fff;
    background: #a63d31;
    cursor: pointer;
    font-size: 16px;
    line-height: 25px;
  }
  .win-close:hover { background: #d95743; }

  .files-toolbar {
    flex: 0 0 48px;
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 8px 12px;
    border-bottom: 1px solid var(--line);
    background: #20232d;
  }
  #files-up {
    border: 1px solid var(--line);
    border-radius: 6px;
    padding: 5px 10px;
    color: var(--text);
    background: var(--panel-3);
    cursor: pointer;
  }
  #files-up:hover { background: #3c4353; }
  .path-label {
    flex: 1;
    min-width: 0;
    padding: 7px 11px;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
    border-radius: 5px;
    color: #d8dbea;
    background: #171920;
    font-family: monospace;
    font-size: 13px;
  }

  #files-list {
    flex: 1;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(112px, 1fr));
    align-content: start;
    gap: 8px;
    padding: 18px;
    overflow: auto;
  }
  .fs-item {
    min-height: 83px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 7px;
    padding: 8px;
    border: 1px solid transparent;
    border-radius: 7px;
    color: var(--text);
    cursor: default;
    font-size: 13px;
    text-align: center;
    word-break: break-word;
  }
  .fs-item.folder { cursor: pointer; }
  .fs-item:hover {
    border-color: rgba(233,84,32,.55);
    background: rgba(233,84,32,.13);
  }
  .file-icon { font-size: 30px; }
  .folder .file-icon { color: #e9b949; }

  #notepad-content {
    flex: 1;
    min-height: 0;
    display: flex;
    flex-direction: column;
    background: #171920;
  }
  #tabs {
    flex: 0 0 39px;
    display: flex;
    align-items: stretch;
    gap: 3px;
    padding: 5px 7px 0;
    overflow-x: auto;
    background: #20232c;
    border-bottom: 1px solid var(--line);
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 9px;
    max-width: 175px;
    padding: 0 10px;
    border: 0;
    border-radius: 6px 6px 0 0;
    color: var(--muted);
    background: transparent;
    cursor: pointer;
    font-size: 12px;
    white-space: nowrap;
  }
  .tab:hover { color: var(--text); background: #2c303b; }
  .tab.active {
    color: var(--text);
    background: #171920;
    box-shadow: inset 0 2px var(--accent);
  }
  .tab-name { overflow: hidden; text-overflow: ellipsis; }
  .tab-x {
    color: #858b9c;
    font-size: 15px;
    line-height: 1;
  }
  .tab-x:hover { color: #fff; }
  #new-tab {
    flex: 0 0 28px;
    height: 28px;
    border: 0;
    border-radius: 5px;
    color: var(--muted);
    background: transparent;
    cursor: pointer;
    font-size: 20px;
  }
  #new-tab:hover { color: white; background: var(--panel-3); }
  #editor {
    flex: 1;
    width: 100%;
    min-height: 0;
    resize: none;
    padding: 18px 20px;
    border: 0;
    outline: none;
    color: #e8eaf1;
    background: #171920;
    font: 14px/1.65 "SFMono-Regular", Consolas, monospace;
  }
  .editor-status {
    padding: 5px 14px;
    border-top: 1px solid var(--line);
    color: #7f8697;
    background: #20232c;
    font-size: 11px;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <div class="brand">Activities</div>
    <div class="status"><span>Workspace 1</span><span>⌁ &nbsp;⌁ &nbsp;▣</span><span id="clock"></span></div>
  </div>

  <section id="files-window" class="window" aria-label="Files">
    <div class="win-titlebar">
      <span class="win-icon">🗂️</span>
      <span class="win-title">Files</span>
      <button class="win-close" type="button" aria-label="Close files">×</button>
    </div>
    <div class="files-toolbar">
      <button id="files-up" type="button" title="Go to parent folder">↑ Up</button>
      <div id="files-path" class="path-label">/</div>
    </div>
    <div id="files-list" aria-label="File listing"></div>
  </section>

  <section id="notepad-window" class="window" aria-label="Notepad">
    <div class="win-titlebar">
      <span class="win-icon">📝</span>
      <span class="win-title">Notepad</span>
      <button class="win-close" type="button" aria-label="Close notepad">×</button>
    </div>
    <div id="notepad-content">
      <div id="tabs"></div>
      <textarea id="editor" spellcheck="false" aria-label="Text editor"></textarea>
      <div class="editor-status">Plain text&nbsp; · &nbsp;Saved automatically</div>
    </div>
  </section>

  <nav id="taskbar" aria-label="Application dock">
    <button id="open-files" class="launcher" type="button" title="Open Files">🗂️<small>Files</small></button>
    <button id="open-notepad" class="launcher" type="button" title="Open Notepad">📝<small>Notepad</small></button>
  </nav>
</div>

<script>
(function () {
  const $ = id => document.getElementById(id);

  const fileSystem = {
    "/": [
      { name: "bin", type: "folder" }, { name: "etc", type: "folder" },
      { name: "home", type: "folder" }, { name: "usr", type: "folder" },
      { name: "var", type: "folder" }
    ],
    "/bin": [
      { name: "bash", type: "file" }, { name: "ls", type: "file" },
      { name: "cp", type: "file" }, { name: "mkdir", type: "file" }
    ],
    "/etc": [
      { name: "hostname", type: "file" }, { name: "hosts", type: "file" },
      { name: "fstab", type: "file" }
    ],
    "/home": [{ name: "user", type: "folder" }],
    "/home/user": [
      { name: "Documents", type: "folder" }, { name: "Downloads", type: "folder" },
      { name: "Pictures", type: "folder" }, { name: "welcome.txt", type: "file" }
    ],
    "/home/user/Documents": [
      { name: "ideas.md", type: "file" }, { name: "project-notes.txt", type: "file" }
    ],
    "/home/user/Downloads": [{ name: "readme.pdf", type: "file" }],
    "/home/user/Pictures": [{ name: "wallpaper.png", type: "file" }],
    "/usr": [
      { name: "bin", type: "folder" }, { name: "lib", type: "folder" },
      { name: "share", type: "folder" }
    ],
    "/usr/bin": [{ name: "python3", type: "file" }, { name: "git", type: "file" }],
    "/usr/lib": [{ name: "packages", type: "folder" }],
    "/usr/share": [{ name: "applications", type: "folder" }],
    "/usr/share/applications": [],
    "/usr/lib/packages": [],
    "/var": [
      { name: "log", type: "folder" }, { name: "tmp", type: "folder" },
      { name: "cache", type: "folder" }
    ],
    "/var/log": [{ name: "system.log", type: "file" }],
    "/var/tmp": [], "/var/cache": []
  };

  let currentPath = "/";
  function renderFiles() {
    $("files-path").textContent = currentPath;
    const list = $("files-list");
    list.innerHTML = "";
    (fileSystem[currentPath] || []).forEach(entry => {
      const item = document.createElement("div");
      item.className = "fs-item" + (entry.type === "folder" ? " folder" : "");
      item.dataset.type = entry.type;
      item.dataset.name = entry.name;
      item.innerHTML = '<span class="file-icon">' + (entry.type === "folder" ? "📁" : "📄") +
        '</span><span>' + entry.name + '</span>';
      list.appendChild(item);
    });
  }
  function navigate(path) {
    currentPath = path || "/";
    renderFiles();
  }
  $("files-list").addEventListener("dblclick", function (event) {
    const item = event.target.closest(".fs-item");
    if (!item || item.dataset.type !== "folder") return;
    navigate(currentPath === "/" ? "/" + item.dataset.name : currentPath + "/" + item.dataset.name);
  });
  $("files-up").addEventListener("click", function () {
    if (currentPath === "/") return;
    const parts = currentPath.split("/").filter(Boolean);
    parts.pop();
    navigate(parts.length ? "/" + parts.join("/") : "/");
  });
  renderFiles();

  const storageKey = "ubuntu-desktop-notepad-tabs-v1";
  let notes = [];
  let activeNote = 0;
  function saveNotes() {
    try { localStorage.setItem(storageKey, JSON.stringify({ notes, activeNote })); } catch (e) {}
  }
  function loadNotes() {
    try {
      const saved = JSON.parse(localStorage.getItem(storageKey));
      if (saved && Array.isArray(saved.notes) && saved.notes.length) {
        notes = saved.notes.map((n, i) => ({
          name: typeof n.name === "string" ? n.name : "Untitled " + (i + 1),
          content: typeof n.content === "string" ? n.content : ""
        }));
        activeNote = Math.max(0, Math.min(Number(saved.activeNote) || 0, notes.length - 1));
        return;
      }
    } catch (e) {}
    notes = [{ name: "Untitled 1", content: "" }];
    activeNote = 0;
    saveNotes();
  }
  function renderTabs() {
    const tabs = $("tabs");
    tabs.innerHTML = "";
    notes.forEach((note, index) => {
      const tab = document.createElement("button");
      tab.type = "button";
      tab.className = "tab" + (index === activeNote ? " active" : "");
      tab.dataset.index = index;
      tab.innerHTML = '<span class="tab-name"></span><span class="tab-x" title="Close tab">×</span>';
      tab.querySelector(".tab-name").textContent = note.name;
      tabs.appendChild(tab);
    });
    const add = document.createElement("button");
    add.type = "button";
    add.id = "new-tab";
    add.title = "New tab";
    add.textContent = "+";
    tabs.appendChild(add);
    $("editor").value = notes[activeNote].content;
  }
  function selectNote(index) {
    notes[activeNote].content = $("editor").value;
    activeNote = index;
    renderTabs();
    saveNotes();
    $("editor").focus();
  }
  $("tabs").addEventListener("click", function (event) {
    if (event.target.closest("#new-tab")) {
      notes[activeNote].content = $("editor").value;
      notes.push({ name: "Untitled " + (notes.length + 1), content: "" });
      activeNote = notes.length - 1;
      renderTabs();
      saveNotes();
      $("editor").focus();
      return;
    }
    const tab = event.target.closest(".tab");
    if (!tab) return;
    const index = Number(tab.dataset.index);
    if (event.target.closest(".tab-x")) {
      notes.splice(index, 1);
      if (!notes.length) notes.push({ name: "Untitled 1", content: "" });
      if (activeNote >= notes.length) activeNote = notes.length - 1;
      else if (index < activeNote) activeNote--;
      renderTabs();
      saveNotes();
      return;
    }
    selectNote(index);
  });
  $("editor").addEventListener("input", function () {
    notes[activeNote].content = this.value;
    saveNotes();
  });
  loadNotes();
  renderTabs();

  function showWindow(id) {
    $(id).classList.add("visible");
    $(id).style.zIndex = ++window.topWindow;
  }
  window.topWindow = 5;
  $("open-files").addEventListener("click", () => showWindow("files-window"));
  $("open-notepad").addEventListener("click", () => showWindow("notepad-window"));
  document.querySelectorAll(".win-close").forEach(button => {
    button.addEventListener("click", () => button.closest(".window").classList.remove("visible"));
  });

  document.querySelectorAll(".window").forEach(win => {
    const bar = win.querySelector(".win-titlebar");
    let dragging = false, offsetX = 0, offsetY = 0;
    bar.addEventListener("pointerdown", event => {
      if (event.target.closest(".win-close")) return;
      dragging = true;
      win.style.zIndex = ++window.topWindow;
      const rect = win.getBoundingClientRect();
      offsetX = event.clientX - rect.left;
      offsetY = event.clientY - rect.top;
      bar.setPointerCapture(event.pointerId);
    });
    bar.addEventListener("pointermove", event => {
      if (!dragging) return;
      const maxX = Math.max(0, window.innerWidth - win.offsetWidth);
      const maxY = Math.max(39, window.innerHeight - win.offsetHeight);
      win.style.left = Math.max(0, Math.min(maxX, event.clientX - offsetX)) + "px";
      win.style.top = Math.max(39, Math.min(maxY, event.clientY - offsetY)) + "px";
    });
    bar.addEventListener("pointerup", () => dragging = false);
    bar.addEventListener("pointercancel", () => dragging = false);
  });

  function updateClock() {
    $("clock").textContent = new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  }
  updateClock();
  setInterval(updateClock, 30000);
})();
</script>
</body>
</html>
